mapper.update:
UPDATE TWORK_INFO_IVST_SUPPLIES 
		SET  ACKEY 				= #{ackey}
	       ,ACNAME 				= #{acname}
	       ,ICGRKEY				= #{icgrkey}
	       ,ICGRNAME 			= #{icgrname}
	       ,CARRYOVER_QTY 		= #{carryover_qty}
	       ,INB_INVQTY 			= #{inb_invqty}
	       ,INB_COSTPRICE 		= #{inb_costprice}			       
    	   ,OUT_INVQTY 			= #{out_invqty}
    	   ,OUT_COSTPRICE   	= #{out_costprice}
           ,REPLACE_INVQTY  	= #{replace_invqty}
    	   ,REPLACE_COSTPRICE   = #{replace_costprice}
    	   ,ADJ_INVQTY          = #{adj_invqty}
    	   ,ADJ_COSTPRICE		= #{adj_costprice}
           ,CLOSING_INVQTY      = #{closing_invqty}
           ,CLOSING_COSTPRICE   = #{closing_costprice}
		   ,UPDATEDATE 			= #{sysdate}
	   	   ,UPDATEURKEY 		= #{surkey}
	WHERE 
	SUBUL_YYMM  = #{subul_yymm} 
	AND CTKEY = #{ctkey} 
	AND LOGGRPCD = #{loggrpcd} 
	AND OWKEY = #{owkey} 
	AND ICKEY = #{ickey}

mapper.delete:
DELETE FROM TWORK_INFO_IVST_SUPPLIES
WHERE 
		SUBUL_YYMM  	= #{subul_yymm} 
		AND CTKEY 		= #{ctkey} 
		AND LOGGRPCD    = #{loggrpcd}
	    AND ICKEY 		= #{ickey}

DELETE FROM TWORK_INFO_IVST_SUPPLIES
WHERE SUBUL_YYMM = SUBSTR(TO_CHAR((TO_DATE(#{subul_yymm} || '01', 'YYYYMMDD') + (1) * INTERVAL '1 month'), 'yyyymm'),1,6)
  AND CTKEY = #{ctkey}
  AND OWKEY = #{owkey}
